SELECT COUNT(DISTINCT postgres_air.airport.city) AS num_cities
FROM postgres_air.flight
JOIN postgres_air.airport ON flight.departure_airport = airport.airport_code;

SELECT COUNT(*) 
FROM postgres_air.passenger AS p
WHERE p.age < 18;

SELECT DISTINCT flight.departure_airport
FROM postgres_air.flight 
JOIN postgres_air.airport ON flight.departure_airport = airport.airport_code;
